#include <stdio.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        if (K == 1) {
            printf("1\n");
        } else if (K <= N / 2) {
            for (int i = 1; i <= K; ++i) {
                printf("%d", 2 * i);
                if (i < K) printf(" ");
            }
            printf("\n");
        } else {
            printf("-1\n");
        }
    }
    return 0;
}

