    if(!(cin >> T)) return 0;
    while (T--) {
        int N, K; 
        cin >> N >> K;
        if (K == 1) {
            cout << 1 << '\n';
        } else if (K <= N / 2) {
            for (int i = 1; i <= K; ++i) {
                cout << 2 * i << (i == K ? '\n' : ' ');
            }
        } else {
            cout << -1 << '\n';
        }
    }
    return 0;
}

