import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        if K == 1:
            out_lines.append('1')
        elif K <= N // 2:
            out_lines.append(' '.join(str(2*i) for i in range(1, K+1)))
        else:
            out_lines.append('-1')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

